 //! UPDATE, and DELETE with correct opcode patterns matching C SQLite behavior.

 use fsqlite_ast::{
-    BinaryOp as AstBinaryOp, ColumnRef, DeleteStatement, Expr, FunctionArgs, InsertSource,
